using System;
using System;
using System.IO;
using SixLabors.ImageSharp;
using SixLabors.ImageSharp.PixelFormats;

namespace HDLG.Tests
{
    public class ImageSetup
    {
        private static bool _initialized = false;
        private static readonly object _lock = new();

        public static void CreateImages()
        {
            if (_initialized) return;
            lock (_lock)
            {
                if (_initialized) return;
                var base64Exif = "";
                File.WriteAllBytes("test.jpg", Convert.FromBase64String(base64Exif));

                var base64NoExif = "";
                File.WriteAllBytes("test_no_exif.jpg", Convert.FromBase64String(base64NoExif));

                var base64Png = "iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8z8BQDwAEhQGAhKmMIQAAAABJRU5ErkJggg==";
                File.WriteAllBytes("test.png", Convert.FromBase64String(base64Png));

                File.WriteAllText("test_invalid.jpg", "invalid image");

                // Create corrupted image to trigger InvalidImageContentException
                byte[] validPng = Convert.FromBase64String("iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNkYPhfDwAChwGA60e6kgAAAABJRU5ErkJggg==");
                byte[] corrupted = new byte[65];
                Array.Copy(validPng, corrupted, 65);
                File.WriteAllBytes("test_corrupted.png", corrupted);

                // Create a perfectly valid test image with EXIF directly via Base64 to test properties reliably
                byte[] validJpegWithExif = Convert.FromBase64String("");
                File.WriteAllBytes("test_valid_exif.jpg", validJpegWithExif);

                // Create a perfectly valid test image without EXIF directly via Base64 to test properties reliably
                byte[] validJpegNoExif = Convert.FromBase64String("");
                File.WriteAllBytes("test_valid_no_exif.jpg", validJpegNoExif);


                // Create a truncated JPEG to cause InvalidImageContentException
                byte[] corruptedJpeg = new byte[30];
                Array.Copy(validJpegNoExif, corruptedJpeg, 30);
                File.WriteAllBytes("test_corrupted.jpg", corruptedJpeg);
                _initialized = true;
            }
        }
    }
}
